for (const item of items) {
  try {
    const staticData = $getWorkflowStaticData('global');
    const execId = ($execution && $execution.id) ? String($execution.id) : 'run_' + Date.now();
    const runData = (staticData.runs && staticData.runs[execId]) ? staticData.runs[execId] : {};
    const initialVulns = runData.initial_vulnerabilities || [];

    // --- BACKFILL fixed_code ---
    // Look at item.json.vulnerabilities (fallback node) or staticData (success node)
    const patcherVulns = runData.patcher_vulnerabilities || item.json.vulnerabilities || [];

    for (const iv of initialVulns) {
      const match = patcherVulns.find(pv => pv.type === iv.type && pv.line_number === iv.line_number);
      if (match && match.fixed_code) {
        iv.fixed_code = match.fixed_code;
      }
    }
    for (const iv of initialVulns) {
      if (!iv.fixed_code) {
        const match = patcherVulns.find(pv => pv.type === iv.type && pv.fixed_code);
        if (match) iv.fixed_code = match.fixed_code;
      }
    }

    item.json.number_of_vulnerabilities_fixed = initialVulns.length;
    const types = initialVulns.map(v => v.type || 'Unknown');
    item.json.types_of_vulnerabilities = [...new Set(types)];
    item.json.vulnerabilities_details = initialVulns.map(v => ({
      type: v.type || 'Unknown',
      original_line_number: v.line_number || 0
    }));

    item.json.vulnerabilities = initialVulns;

    try {
      item.json.absolute_original_code = $('Webhook').first().json.body.code;
    } catch (e) {
      item.json.absolute_original_code = $('Init Loop Counter').first()?.json?.original_code || '';
    }

    // FIXED: Use .last() instead of .first() for the fallback code string
    if (!item.json.full_corrected_code) {
      item.json.full_corrected_code =
        item.json.audited_code ||
        $('Max Retries Reached?').last()?.json?.code || '';
    }

    if (staticData.runs && staticData.runs[execId]) {
      delete staticData.runs[execId];
    }

  } catch (error) {
    item.json.error = 'Failed to prepare final data: ' + error.message;
  }
}
return items;

