// CODE IN JAVASCRIPT
// Extracts patched Python from Patcher Agent output.
// ============================================================

for (const item of items) {
  try {
    let rawOutput = item.json.output;

    if (typeof rawOutput === 'string') {
      // 1. Strip <tool_call>...</tool_call> and stray XML/HTML tags
      rawOutput = rawOutput.replace(/<tool_call>[\s\S]*?<\/tool_call>/gi, '');
      rawOutput = rawOutput.replace(/<[a-zA-Z_][^>]*\/?>|<\/[a-zA-Z_][^>]*>/g, '');

      // 2. Fix known field typos
      rawOutput = rawOutput.replace(/"vureabilities"\s*:/g, '"vulnerabilities":');
      rawOutput = rawOutput.replace(/"vulnerabilites"\s*:/g, '"vulnerabilities":');
      rawOutput = rawOutput.replace(/"vulnarabilities"\s*:/g, '"vulnerabilities":');

      // 3. Strip markdown fences
      rawOutput = rawOutput.replace(/^```json\s*|\s*```$/g, '').trim();
      rawOutput = rawOutput.replace(/^```\s*|\s*```$/g, '').trim();

      try {
        const parsed = JSON.parse(rawOutput);
        item.json.code = parsed.full_corrected_code || rawOutput;
        item.json.full_corrected_code = parsed.full_corrected_code || rawOutput;
        item.json.vulnerabilities = parsed.vulnerabilities || [];
      } catch (e) {
        // Not valid JSON — treat as raw Python
        item.json.code = rawOutput;
        item.json.full_corrected_code = rawOutput;
        item.json.vulnerabilities = [];
      }

    } else if (typeof rawOutput === 'object' && rawOutput !== null) {
      item.json.code = rawOutput.full_corrected_code || '';
      item.json.full_corrected_code = rawOutput.full_corrected_code || '';
      item.json.vulnerabilities = rawOutput.vulnerabilities || [];
    }

    // 4. Sanity check: if extracted code is still a JSON blob, re-extract
    const extracted = (item.json.code || '').trim();
    if (extracted.startsWith('{') || extracted.startsWith('[')) {
      try {
        const reparsed = JSON.parse(extracted);
        if (reparsed.full_corrected_code) {
          // FIXED TYPO HERE (was reparparsed)
          item.json.code = reparsed.full_corrected_code;
          item.json.full_corrected_code = reparsed.full_corrected_code;
        } else {
          throw new Error('no full_corrected_code in re-parsed blob');
        }
      } catch (e) {
        // FIXED .first() to .last() HERE
        const fallback = $('Max Retries Reached?').last()?.json?.code || '';
        item.json.code = fallback;
        item.json.full_corrected_code = fallback;
        item.json.parse_error = 'Patcher output unrecognised; used last known good code';
      }
    }

    // 5. Save Patcher vulnerabilities (with fixed_code) to workflow static data
    const patcherVulns = item.json.vulnerabilities || [];
    if (patcherVulns.length > 0) {
      const staticData = $getWorkflowStaticData('global');
      const execId = ($execution && $execution.id) ? String($execution.id) : 'run_' + Date.now();
      if (!staticData.runs) staticData.runs = {};
      if (!staticData.runs[execId]) staticData.runs[execId] = {};
      staticData.runs[execId].patcher_vulnerabilities = JSON.parse(JSON.stringify(patcherVulns));
    }

  } catch (error) {
    item.json.error = error.message;
  }
}

return items;

